            sheet3.addRow(createArray('test', 'these', 'values'));
            sheet3.addRow(createArray('and', 'also', 'these', 'values'));
            await workbook3.xlsx.writeFile('file3.xlsx');
        })();
    `, {excelJS: excelJS, createArray: function (...args) { return [...args]} });
